// Define the threshold for 23 hours and 55 minutes in milliseconds
const threshold = (23 * 60 * 60 * 1000) + (55 * 60 * 1000);

// Process each item to compare the times
const output = inputData.map(item => {
    const createdTime = new Date(item.json.created);
    const currentTime = new Date(item.json.currentTimeGMT);

    // Calculate the difference in milliseconds
    const differenceInMs = currentTime - createdTime;

    // Check if the difference is greater than the threshold
    const isGreaterThanThreshold = differenceInMs > threshold;

    // Return the result with both created time and comparison result
    return {
        json: {
            created: item.json.created,
            currentTimeGMT: item.json.currentTimeGMT,
            isGreaterThanThreshold: isGreaterThanThreshold,
            phone: item.json.phone
        }
    };
});

